/*
  # Refine Onboarding Email Template

  1. Changes
    - "Objekte, Einheiten und Mietvertraege" -> "Immobilien, Einheiten und Mietvertraege"
    - Add decorative graphic before the 3 steps section
    - Step 1 instructions: "Objekte" -> "Immobilien", "Objekt hinzufuegen" -> "Immobilie hinzufuegen"
    - "Was ist eine Einheit?" box styled as a distinct info-box with blue left border
    - Reviews: Replace Markus F. with Sandra K. (image + text from marketing site), add avatar images
    - Move "Schnell Objekte & Einheiten importieren" box above the first "Jetzt loslegen" CTA

  2. Security
    - No schema changes, data-only update
*/

DO $$
DECLARE
  v_html text;
  v_text text;
BEGIN

v_html := E'<!DOCTYPE html>\n<html lang="de">\n<head>\n<meta charset="utf-8">\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n<meta http-equiv="X-UA-Compatible" content="IE=edge">\n<title>Willkommen bei rentably</title>\n</head>\n<body style="margin: 0; padding: 0; background-color: #f5f5f5; font-family: \'Manrope\', Arial, Helvetica, sans-serif; -webkit-text-size-adjust: none; text-size-adjust: none;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #f5f5f5;">\n<tr><td align="center" style="padding: 32px 16px;">\n<table width="600" border="0" cellpadding="0" cellspacing="0" style="max-width: 600px; width: 100%; background-color: #ffffff; border-radius: 8px; overflow: hidden;">\n\n<!-- HEADER -->\n<tr><td style="padding: 28px 32px 20px; text-align: center; border-bottom: 1px solid #eee;">\n<a href="https://rentab.ly" target="_blank" style="display: inline-block;">\n<img src="https://6f36f82794.imgdist.com/pub/bfra/2bnm3c1v/dzm/8g5/nzj/rentably-logo.svg" alt="rentably" width="180" style="display: block; height: auto; border: 0;" />\n</a>\n</td></tr>\n\n<!-- 1. HERO -->\n<tr><td style="padding: 36px 32px 0;">\n<h1 style="margin: 0 0 16px; color: #1E1E24; font-size: 22px; font-weight: 700; line-height: 1.35;">Willkommen bei rentably</h1>\n<p style="margin: 0 0 8px; color: #555; font-size: 14px; line-height: 1.65;">Hallo <strong style="color: #1E1E24;">{{userName}}</strong>,</p>\n<p style="margin: 0; color: #555; font-size: 14px; line-height: 1.65;">sch&ouml;n, dass Sie hier sind. Ihr 30-t&auml;giger Pro-Test ist jetzt aktiv &ndash; Sie k&ouml;nnen ab sofort alle Funktionen nutzen. Damit der Einstieg leicht f&auml;llt, zeigen wir Ihnen die drei wichtigsten Schritte f&uuml;r den Start.</p>\n</td></tr>\n\n<!-- 2. WARUM LOHNT SICH DAS? -->\n<tr><td style="padding: 28px 32px 0;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #f8fafc; border-radius: 8px; border: 1px solid #eef2f6;">\n<tr><td style="padding: 22px 20px;">\n<p style="margin: 0 0 14px; color: #1E1E24; font-size: 15px; font-weight: 700; line-height: 1.3;">Warum lohnt sich der Einstieg?</p>\n<table width="100%" border="0" cellpadding="0" cellspacing="0">\n<tr><td style="padding: 0 0 8px;"><table border="0" cellpadding="0" cellspacing="0"><tr>\n<td width="24" valign="top" style="padding-top: 1px; color: #3c8af7; font-size: 14px;">&#10003;</td>\n<td style="color: #555; font-size: 13px; line-height: 1.55;"><strong style="color: #1E1E24;">Kompletter &Uuml;berblick</strong> &ndash; Immobilien, Einheiten und Mietvertr&auml;ge an einem Ort</td>\n</tr></table></td></tr>\n<tr><td style="padding: 0 0 8px;"><table border="0" cellpadding="0" cellspacing="0"><tr>\n<td width="24" valign="top" style="padding-top: 1px; color: #3c8af7; font-size: 14px;">&#10003;</td>\n<td style="color: #555; font-size: 13px; line-height: 1.55;"><strong style="color: #1E1E24;">Mietkonten im Blick</strong> &ndash; Zahlungseing&auml;nge automatisch erfassen, kein manuelles Nachhalten mehr</td>\n</tr></table></td></tr>\n<tr><td style="padding: 0 0 8px;"><table border="0" cellpadding="0" cellspacing="0"><tr>\n<td width="24" valign="top" style="padding-top: 1px; color: #3c8af7; font-size: 14px;">&#10003;</td>\n<td style="color: #555; font-size: 13px; line-height: 1.55;"><strong style="color: #1E1E24;">Alles digital</strong> &ndash; Dokumente, Kommunikation und Abrechnungen zentral und jederzeit abrufbar</td>\n</tr></table></td></tr>\n<tr><td style="padding: 0;"><table border="0" cellpadding="0" cellspacing="0"><tr>\n<td width="24" valign="top" style="padding-top: 1px; color: #3c8af7; font-size: 14px;">&#10003;</td>\n<td style="color: #555; font-size: 13px; line-height: 1.55;"><strong style="color: #1E1E24;">Weniger Aufwand</strong> &ndash; Betriebskostenabrechnungen in Minuten statt Stunden erstellen</td>\n</tr></table></td></tr>\n</table>\n</td></tr>\n</table>\n</td></tr>\n\n<!-- DECORATIVE GRAPHIC BEFORE STEPS -->\n<tr><td style="padding: 32px 32px 0; text-align: center;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background: linear-gradient(135deg, #EEF4FF 0%, #f0f7ff 50%, #EEF4FF 100%); border-radius: 10px; border: 1px solid #DDE7FF;">\n<tr><td style="padding: 28px 20px; text-align: center;">\n<!-- Three connected step circles -->\n<table border="0" cellpadding="0" cellspacing="0" align="center"><tr>\n<td style="text-align: center;">\n<div style="width: 48px; height: 48px; border-radius: 50%; background-color: #ffffff; border: 2px solid #3c8af7; text-align: center; line-height: 48px; font-size: 18px; font-weight: 700; color: #3c8af7; display: inline-block;">1</div>\n</td>\n<td style="padding: 0 6px;"><div style="width: 32px; height: 2px; background-color: #3c8af7; opacity: 0.3;"></div></td>\n<td style="text-align: center;">\n<div style="width: 48px; height: 48px; border-radius: 50%; background-color: #ffffff; border: 2px solid #3c8af7; text-align: center; line-height: 48px; font-size: 18px; font-weight: 700; color: #3c8af7; display: inline-block;">2</div>\n</td>\n<td style="padding: 0 6px;"><div style="width: 32px; height: 2px; background-color: #3c8af7; opacity: 0.3;"></div></td>\n<td style="text-align: center;">\n<div style="width: 48px; height: 48px; border-radius: 50%; background-color: #ffffff; border: 2px solid #3c8af7; text-align: center; line-height: 48px; font-size: 18px; font-weight: 700; color: #3c8af7; display: inline-block;">3</div>\n</td>\n</tr>\n<tr>\n<td style="text-align: center; padding-top: 6px;"><span style="font-size: 10px; color: #3c8af7; font-weight: 600;">Immobilie</span></td>\n<td></td>\n<td style="text-align: center; padding-top: 6px;"><span style="font-size: 10px; color: #3c8af7; font-weight: 600;">Einheit</span></td>\n<td></td>\n<td style="text-align: center; padding-top: 6px;"><span style="font-size: 10px; color: #3c8af7; font-weight: 600;">Mieter</span></td>\n</tr></table>\n<p style="margin: 16px 0 0; color: #3c8af7; font-size: 11px; font-weight: 700; text-transform: uppercase; letter-spacing: 1.5px;">Ihre ersten 3 Schritte</p>\n<p style="margin: 4px 0 0; color: #888; font-size: 13px; line-height: 1.5;">So richten Sie rentably in wenigen Minuten ein.</p>\n</td></tr>\n</table>\n</td></tr>\n\n<!-- 3. SCHRITT 1: IMMOBILIE -->\n<tr><td style="padding: 20px 32px 0;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #f8fafc; border-radius: 8px; border: 1px solid #eef2f6;">\n<tr><td style="padding: 22px 20px;">\n<table border="0" cellpadding="0" cellspacing="0" width="100%"><tr>\n<td width="44" valign="top">\n<div style="width: 34px; height: 34px; border-radius: 50%; background-color: #EEF4FF; border: 1px solid #DDE7FF; text-align: center; line-height: 34px; font-size: 14px; font-weight: 700; color: #3c8af7;">1</div>\n</td>\n<td valign="top">\n<p style="margin: 0 0 6px; color: #1E1E24; font-size: 15px; font-weight: 700; line-height: 1.3;">Immobilie anlegen</p>\n<p style="margin: 0 0 14px; color: #666; font-size: 13px; line-height: 1.6;">Erstellen Sie Ihre erste Immobilie in rentably und hinterlegen Sie die wichtigsten Daten. So haben Sie immer einen vollst&auml;ndigen &Uuml;berblick &ndash; egal ob Mehrfamilienhaus, Eigentumswohnung oder Gewerbeeinheit.</p>\n<p style="margin: 0 0 6px; color: #1E1E24; font-size: 12px; font-weight: 600;">So funktioniert&#39;s:</p>\n<table border="0" cellpadding="0" cellspacing="0">\n<tr><td style="padding: 0 0 3px; color: #666; font-size: 12px; line-height: 1.5;"><span style="color: #3c8af7; font-weight: 600;">1.</span>&nbsp; Melden Sie sich bei rentably an</td></tr>\n<tr><td style="padding: 0 0 3px; color: #666; font-size: 12px; line-height: 1.5;"><span style="color: #3c8af7; font-weight: 600;">2.</span>&nbsp; Gehen Sie zu &bdquo;Immobilien&ldquo; und klicken Sie auf &bdquo;Immobilie hinzuf&uuml;gen&ldquo;</td></tr>\n<tr><td style="padding: 0; color: #666; font-size: 12px; line-height: 1.5;"><span style="color: #3c8af7; font-weight: 600;">3.</span>&nbsp; W&auml;hlen Sie den Immobilientyp und geben Sie die Adresse ein</td></tr>\n</table>\n</td>\n</tr></table>\n</td></tr>\n</table>\n</td></tr>\n\n<!-- 4. SCHRITT 2: EINHEIT -->\n<tr><td style="padding: 12px 32px 0;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #f8fafc; border-radius: 8px; border: 1px solid #eef2f6;">\n<tr><td style="padding: 22px 20px;">\n<table border="0" cellpadding="0" cellspacing="0" width="100%"><tr>\n<td width="44" valign="top">\n<div style="width: 34px; height: 34px; border-radius: 50%; background-color: #EEF4FF; border: 1px solid #DDE7FF; text-align: center; line-height: 34px; font-size: 14px; font-weight: 700; color: #3c8af7;">2</div>\n</td>\n<td valign="top">\n<p style="margin: 0 0 6px; color: #1E1E24; font-size: 15px; font-weight: 700; line-height: 1.3;">Einheiten hinzuf&uuml;gen</p>\n<p style="margin: 0 0 14px; color: #666; font-size: 13px; line-height: 1.6;">Nachdem Ihre Immobilie angelegt ist, f&uuml;gen Sie die zugeh&ouml;rigen Einheiten hinzu. Damit stellen Sie sicher, dass jeder Einheit sp&auml;ter ein Mietverh&auml;ltnis und die richtigen Buchungen zugeordnet werden.</p>\n<p style="margin: 0 0 6px; color: #1E1E24; font-size: 12px; font-weight: 600;">Warum ist das wichtig?</p>\n<table border="0" cellpadding="0" cellspacing="0">\n<tr><td style="padding: 0 0 3px; color: #666; font-size: 12px; line-height: 1.5;"><span style="color: #3c8af7;">&#10003;</span>&nbsp; Mietverh&auml;ltnisse und Zahlungen korrekt zuordnen</td></tr>\n<tr><td style="padding: 0 0 3px; color: #666; font-size: 12px; line-height: 1.5;"><span style="color: #3c8af7;">&#10003;</span>&nbsp; Voraussetzung f&uuml;r die Nebenkostenabrechnung</td></tr>\n<tr><td style="padding: 0 0 14px; color: #666; font-size: 12px; line-height: 1.5;"><span style="color: #3c8af7;">&#10003;</span>&nbsp; &Uuml;bersicht &uuml;ber vermietete Einheiten und Leerstand</td></tr>\n</table>\n<!-- INFO BOX: Was ist eine Einheit? -->\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #EEF4FF; border-radius: 6px; border-left: 4px solid #3c8af7;">\n<tr><td style="padding: 14px 16px;">\n<table border="0" cellpadding="0" cellspacing="0" width="100%"><tr>\n<td width="24" valign="top" style="padding-top: 1px; font-size: 16px;">&#9432;</td>\n<td valign="top">\n<p style="margin: 0 0 4px; color: #1E1E24; font-size: 12px; font-weight: 700;">Was ist eine Einheit?</p>\n<p style="margin: 0; color: #555; font-size: 12px; line-height: 1.55;">Eine Einheit ist z.&thinsp;B. eine Wohnung, eine Garage / ein Stellplatz oder eine Gewerbefl&auml;che. Alles, was einen eigenen Mietvertrag erh&auml;lt, kann eine Einheit sein. <strong style="color: #1E1E24;">Beispiel:</strong> Ein Objekt mit 10 Wohnungen, 3 Stellpl&auml;tzen und einem Ladenlokal enth&auml;lt insgesamt <strong style="color: #1E1E24;">14 Einheiten</strong>.</p>\n</td>\n</tr></table>\n</td></tr>\n</table>\n</td>\n</tr></table>\n</td></tr>\n</table>\n</td></tr>\n\n<!-- 5. SCHRITT 3: MIETVERHAELTNIS -->\n<tr><td style="padding: 12px 32px 0;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #f8fafc; border-radius: 8px; border: 1px solid #eef2f6;">\n<tr><td style="padding: 22px 20px;">\n<table border="0" cellpadding="0" cellspacing="0" width="100%"><tr>\n<td width="44" valign="top">\n<div style="width: 34px; height: 34px; border-radius: 50%; background-color: #EEF4FF; border: 1px solid #DDE7FF; text-align: center; line-height: 34px; font-size: 14px; font-weight: 700; color: #3c8af7;">3</div>\n</td>\n<td valign="top">\n<p style="margin: 0 0 6px; color: #1E1E24; font-size: 15px; font-weight: 700; line-height: 1.3;">Mietverh&auml;ltnis erfassen</p>\n<p style="margin: 0 0 14px; color: #666; font-size: 13px; line-height: 1.6;">Jetzt legen Sie Ihre Mietverh&auml;ltnisse direkt in den passenden Einheiten an. So haben Sie Mietzahlungen, Vertr&auml;ge und Mieterdaten vollst&auml;ndig und &uuml;bersichtlich an einem Ort.</p>\n<p style="margin: 0 0 6px; color: #1E1E24; font-size: 12px; font-weight: 600;">Vorteile der digitalen Mietverwaltung:</p>\n<table border="0" cellpadding="0" cellspacing="0">\n<tr><td style="padding: 0 0 3px; color: #666; font-size: 12px; line-height: 1.5;"><span style="color: #3c8af7;">&#10003;</span>&nbsp; Automatische Mietbuchungen und Zahlungserinnerungen</td></tr>\n<tr><td style="padding: 0 0 3px; color: #666; font-size: 12px; line-height: 1.5;"><span style="color: #3c8af7;">&#10003;</span>&nbsp; Mieterdaten und Dokumente zentral gespeichert</td></tr>\n<tr><td style="padding: 0; color: #666; font-size: 12px; line-height: 1.5;"><span style="color: #3c8af7;">&#10003;</span>&nbsp; &Uuml;bersicht &uuml;ber alle aktiven Mietverh&auml;ltnisse</td></tr>\n</table>\n</td>\n</tr></table>\n</td></tr>\n</table>\n</td></tr>\n\n<!-- 6. IMPORT HINWEIS (moved before CTA) -->\n<tr><td style="padding: 20px 32px 0;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #f8fafc; border-radius: 8px; border: 1px solid #eef2f6;">\n<tr><td style="padding: 20px;">\n<p style="margin: 0 0 6px; color: #1E1E24; font-size: 14px; font-weight: 700; line-height: 1.3;">Schnell Immobilien &amp; Einheiten importieren</p>\n<p style="margin: 0 0 10px; color: #666; font-size: 13px; line-height: 1.6;">Je schneller Ihre Daten in rentably hinterlegt sind, desto effizienter wird Ihre Verwaltung.</p>\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #EEF4FF; border-radius: 6px; border-left: 4px solid #3c8af7;">\n<tr><td style="padding: 10px 14px;">\n<p style="margin: 0; color: #555; font-size: 12px; line-height: 1.55;"><strong style="color: #1E1E24;">Tipp:</strong> Falls Sie bereits bestehende Daten haben, k&ouml;nnen Sie diese einfach per <strong style="color: #1E1E24;">CSV- oder Excel-Upload</strong> importieren &ndash; kein manuelles Eintippen n&ouml;tig.</p>\n</td></tr>\n</table>\n</td></tr>\n</table>\n</td></tr>\n\n<!-- PRIMARY CTA -->\n<tr><td style="padding: 28px 32px 0; text-align: center;">\n<a href="{{dashboard_link}}" style="display: inline-block; background-color: #3c8af7; color: #ffffff; text-decoration: none; padding: 13px 40px; border-radius: 8px; font-size: 15px; font-weight: 700; letter-spacing: 0.01em;">Jetzt loslegen</a>\n</td></tr>\n\n<!-- 7. TESTIMONIALS -->\n<tr><td style="padding: 36px 32px 0;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="border-top: 1px solid #eee;">\n<tr><td style="padding: 28px 0 0; text-align: center;">\n<p style="margin: 0 0 4px; color: #1E1E24; font-size: 15px; font-weight: 700;">Das sagen unsere Nutzer</p>\n<p style="margin: 0 0 20px; color: #888; font-size: 12px;">Zufriedene Vermieter verwalten ihre Immobilien mit rentably.</p>\n</td></tr>\n</table>\n\n<!-- Testimonial 1: Thomas M. -->\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #f8fafc; border-radius: 8px; border: 1px solid #eef2f6; margin-bottom: 10px;">\n<tr><td style="padding: 18px;">\n<p style="margin: 0 0 6px; color: #f59e0b; font-size: 12px; letter-spacing: 1px;">&#9733;&#9733;&#9733;&#9733;&#9733;</p>\n<p style="margin: 0 0 12px; color: #555; font-size: 13px; line-height: 1.55; font-style: italic;">&bdquo;Seit ich rentably nutze, habe ich endlich den &Uuml;berblick &uuml;ber alle Mietverh&auml;ltnisse. Die Betriebskostenabrechnung dauert keine Stunden mehr, sondern Minuten.&ldquo;</p>\n<table border="0" cellpadding="0" cellspacing="0"><tr>\n<td width="40" valign="middle"><img src="https://images.pexels.com/photos/220453/pexels-photo-220453.jpeg?auto=compress&cs=tinysrgb&w=200" alt="Thomas M." width="36" height="36" style="border-radius: 50%; display: block; object-fit: cover;" /></td>\n<td valign="middle" style="padding-left: 10px;">\n<p style="margin: 0; color: #1E1E24; font-size: 12px; font-weight: 600;">Thomas M.</p>\n<p style="margin: 0; color: #999; font-size: 11px;">Vermieter, 4 Wohnungen</p>\n</td>\n</tr></table>\n</td></tr>\n</table>\n\n<!-- Testimonial 2: Sandra K. -->\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #f8fafc; border-radius: 8px; border: 1px solid #eef2f6;">\n<tr><td style="padding: 18px;">\n<p style="margin: 0 0 6px; color: #f59e0b; font-size: 12px; letter-spacing: 1px;">&#9733;&#9733;&#9733;&#9733;&#9733;</p>\n<p style="margin: 0 0 12px; color: #555; font-size: 13px; line-height: 1.55; font-style: italic;">&bdquo;Ich habe lange nach einer einfachen L&ouml;sung gesucht. rentably ist genau das &ndash; &uuml;bersichtlich, schnell und vor allem kostenlos f&uuml;r meine Bed&uuml;rfnisse.&ldquo;</p>\n<table border="0" cellpadding="0" cellspacing="0"><tr>\n<td width="40" valign="middle"><img src="https://images.pexels.com/photos/774909/pexels-photo-774909.jpeg?auto=compress&cs=tinysrgb&w=200" alt="Sandra K." width="36" height="36" style="border-radius: 50%; display: block; object-fit: cover;" /></td>\n<td valign="middle" style="padding-left: 10px;">\n<p style="margin: 0; color: #1E1E24; font-size: 12px; font-weight: 600;">Sandra K.</p>\n<p style="margin: 0; color: #999; font-size: 11px;">Eigent&uuml;merin, 2 Objekte</p>\n</td>\n</tr></table>\n</td></tr>\n</table>\n</td></tr>\n\n<!-- 8. CHECKLISTE -->\n<tr><td style="padding: 28px 32px 0;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="border-top: 1px solid #eee;">\n<tr><td style="padding: 24px 0 0;">\n<p style="margin: 0 0 16px; color: #1E1E24; font-size: 15px; font-weight: 700; line-height: 1.3;">Ihre Checkliste f&uuml;r den Start</p>\n<table width="100%" border="0" cellpadding="0" cellspacing="0">\n<tr><td style="padding: 0 0 6px;"><table border="0" cellpadding="0" cellspacing="0"><tr>\n<td width="22" valign="top" style="padding-top: 1px; color: #22c55e; font-size: 14px;">&#10003;</td>\n<td style="color: #999; font-size: 13px; line-height: 1.4; text-decoration: line-through;">Konto erstellt</td>\n</tr></table></td></tr>\n<tr><td style="padding: 0 0 6px;"><table border="0" cellpadding="0" cellspacing="0"><tr>\n<td width="22" valign="top" style="padding-top: 2px;"><div style="width: 14px; height: 14px; border-radius: 3px; border: 1.5px solid #ccc;"></div></td>\n<td style="color: #555; font-size: 13px; line-height: 1.4;"><strong style="color:#1E1E24;">Erste Immobilie anlegen</strong> <span style="color: #999;">&ndash; Grundlage f&uuml;r Ihr Immobilienmanagement</span></td>\n</tr></table></td></tr>\n<tr><td style="padding: 0 0 6px;"><table border="0" cellpadding="0" cellspacing="0"><tr>\n<td width="22" valign="top" style="padding-top: 2px;"><div style="width: 14px; height: 14px; border-radius: 3px; border: 1.5px solid #ccc;"></div></td>\n<td style="color: #555; font-size: 13px; line-height: 1.4;"><strong style="color:#1E1E24;">Einheit anlegen</strong> <span style="color: #999;">&ndash; Wohnung, Garage oder Gewerbe</span></td>\n</tr></table></td></tr>\n<tr><td style="padding: 0 0 6px;"><table border="0" cellpadding="0" cellspacing="0"><tr>\n<td width="22" valign="top" style="padding-top: 2px;"><div style="width: 14px; height: 14px; border-radius: 3px; border: 1.5px solid #ccc;"></div></td>\n<td style="color: #555; font-size: 13px; line-height: 1.4;"><strong style="color:#1E1E24;">Mietverh&auml;ltnis erfassen</strong> <span style="color: #999;">&ndash; Ausgangspunkt f&uuml;r Ihre Mietverwaltung</span></td>\n</tr></table></td></tr>\n<tr><td style="padding: 0 0 6px;"><table border="0" cellpadding="0" cellspacing="0"><tr>\n<td width="22" valign="top" style="padding-top: 2px;"><div style="width: 14px; height: 14px; border-radius: 3px; border: 1.5px solid #ccc;"></div></td>\n<td style="color: #555; font-size: 13px; line-height: 1.4;"><strong style="color:#1E1E24;">Bankkonto verkn&uuml;pfen</strong> <span style="color: #999;">&ndash; automatische Mieteingangskontrolle</span></td>\n</tr></table></td></tr>\n<tr><td style="padding: 0 0 6px;"><table border="0